import json
import pandas as pd
from collections import Counter
import re

# Read the full data from the file
file_path = locals()['var_functions.query_db:26']
with open(file_path, 'r') as f:
    businesses = json.load(f)

# Filter businesses that accept credit cards and extract categories
credit_card_businesses = []
category_counts = Counter()
category_business_ids = {}

for biz in businesses:
    attributes = biz.get('attributes', {})
    # Check if business accepts credit cards
    if isinstance(attributes, dict) and attributes.get('BusinessAcceptsCreditCards') == 'True':
        business_id = biz.get('business_id', '')
        business_ref = business_id.replace('businessid_', 'businessref_')
        description = biz.get('description', '')

        # Extract categories from description
        categories = []
        if 'services in' in description:
            categories_str = description.split('services in')[-1].strip()
            # Remove trailing period and split by commas
            categories_str = categories_str.rstrip('.')
            categories = [cat.strip() for cat in categories_str.split(',') if cat.strip()]
        elif 'services including' in description or 'including' in description:
            if 'services including' in description:
                categories_str = description.split('services including')[-1].strip()
            else:
                # Try to find categories after "including"
                parts = description.split('including')
                if len(parts) > 1:
                    categories_str = parts[-1].strip()

            # Remove trailing period and split by commas and "and"
            categories_str = categories_str.rstrip('.')
            # Split by comma and "and"
            raw_categories = []
            for part in categories_str.split(','):
                part = part.strip()
                if ' and ' in part:
                    subparts = part.split(' and ')
                    raw_categories.extend([p.strip() for p in subparts if p.strip()])
                else:
                    if part:
                        raw_categories.append(part)

            # Clean up categories
            categories = []
            for cat in raw_categories:
                # Remove leading/trailing spaces and common conjunctions
                cat = cat.strip()
                if cat and cat not in ['and', 'or']:
                    categories.append(cat)

        # Clean up category names further
        cleaned_categories = []
        for cat in categories:
            # Remove 'and' from the beginning or end
            cat = cat.strip()
            if cat.startswith('and '):
                cat = cat[4:].strip()
            if cat.endswith(' and'):
                cat = cat[:-4].strip()
            if cat:
                cleaned_categories.append(cat)

        if cleaned_categories:
            for cat in cleaned_categories:
                category_counts[cat] += 1
                if cat not in category_business_ids:
                    category_business_ids[cat] = []
                category_business_ids[cat].append(business_ref)

        credit_card_businesses.append({
            'business_id': business_id,
            'business_ref': business_ref,
            'categories': cleaned_categories,
            'description': description
        })

print('__RESULT__:')
print(json.dumps({
    'total_credit_card_businesses': len(credit_card_businesses),
    'category_counts': dict(category_counts.most_common(10)),
    'sample_businesses': credit_card_businesses[:5]
}))
